const inject_targets = [
  'https://jobs.rainmakers.co/employer?notify=logged',
  'https://jobs.rainmakers.co/employer?notify=created',
  'https://jobs.rainmakers.co/employer',
  'https://jobs.rainmakers.co/employer/profile',
  'https://jobs.rainmakers.co/employer/jobs',
  'https://jobs.rainmakers.co/employer/applicants',
  'https://jobs.rainmakers.co/employer/billing',
  'https://jobs.rainmakers.co/employer/subscriptions',
  'https://jobs.rainmakers.co/employer/team',
  'file:///Users/vkozyrev/Documents/Rainmakers/niceboard_custom_scripts/test.html'
];

window.onload = (event) => {
  if (inject_targets.includes(window.location.href)) {
    const style = document.createElement("style");
    style.textContent = STYLES;
    document.head.appendChild(style);


    document
      .getElementsByClassName("inner")
      .item(2)
      .innerHTML = HTML_CONTENT;
  }
};
